/**
 * Defines generic types filter for ledger records.
 * Currently used on:
 * - access rules
 * - wallet routes
 * - effects
 * Each of those can extend or override this filter
 * if necessary.
 */
type ComparisonOperators<T> = {
    $eq?: T;
    $ne?: T;
    $gt?: T extends number | Date ? T : never;
    $gte?: T extends number | Date ? T : never;
    $lt?: T extends number | Date ? T : never;
    $lte?: T extends number | Date ? T : never;
    $in?: T[];
    $nin?: T[];
    $isNull?: boolean;
};
type LogicalOperators<T> = {
    $and?: MingoFilter<T>[];
    $or?: MingoFilter<T>[];
    $nor?: MingoFilter<T>[];
    $not?: MingoFilter<T>;
};
type ElementOperators = {
    $exists?: boolean;
    $type?: string | number;
};
type EvaluationOperators = {
    $regex?: RegExp | string;
    $options?: string;
    $mod?: [number, number];
    $text?: {
        $search: string;
    };
    $where?: string | ((this: any) => boolean);
};
type ArrayOperators<T> = {
    $all?: T[];
    $elemMatch?: MingoFilter<T extends Array<infer U> ? U : T>;
    $size?: number;
};
export type FieldQueryOperators<T> = T extends Array<infer U> ? ComparisonOperators<T> & ElementOperators & EvaluationOperators & ArrayOperators<U> : ComparisonOperators<T> & ElementOperators & EvaluationOperators;
export type MingoFilter<T> = LogicalOperators<T> & {
    [K in keyof T]?: FieldQueryOperators<T[K]> | string | number | boolean | null | undefined;
};
export type GenericMingoFilter = {
    [key: string]: FieldQueryOperators<any> | any;
} & {
    $and?: GenericMingoFilter[];
    $or?: GenericMingoFilter[];
    $nor?: GenericMingoFilter[];
    $not?: GenericMingoFilter;
};
export type LedgerFilter = GenericMingoFilter;
export {};
